good-example.code-block:
package com.acme.shop.ordering;

import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.modulith.test.ApplicationModuleTest;

@ApplicationModuleTest
class OrderingModuleTests {

    @Autowired OrderApi orders;

    @Test
    void placesOrderThroughModuleApi() {
        orders.placeOrder("customer-123");
    }
}

package com.acme.shop.ordering;

import org.junit.jupiter.api.Test;
import org.springframework.modulith.test.ApplicationModuleTest;
import org.springframework.modulith.test.Scenario;

@ApplicationModuleTest
class OrderingEventsTests {

    @Test
    void publishesOrderPlaced(Scenario scenario) {
        scenario.stimulate(() -> orders.placeOrder("customer-123"))
            .andWaitForEventOfType(OrderPlaced.class)
            .toArriveAndVerify(event -> {
                assertThat(event.customerId()).isEqualTo("customer-123");
            });
    }
}

