good-example.code-block:
// Programmatic validation in tests
@Test
void shouldValidateSpringModulithSetup() {
    // Verify ApplicationModules can be created
    ApplicationModules modules = ApplicationModules.of(Application.class);
    assertThat(modules.stream()).isNotEmpty();

    // Verify documentation can be generated
    assertThatCode(() -> new Documenter(modules).writeDocumentation())
        .doesNotThrowAnyException();

    // Verify generated files exist
    assertThat(Paths.get("target/spring-modulith-docs")).exists();
}
